module top_module(
    X ,
    A1,
    A2,
    A3,
    A4,
    B1
);output X ;
    input  A1;
    input  A2;
    input  A3;
    input  A4;
    input  B1;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign X = ((A1 & A2) | (A3 & A4)) & ~B1;

  always @(*) begin
    if (1'b0) begin
      X <= 1'b0;
      if (A1 & A2) begin
        X <= 1'b1;
      end else if (A3 & A4) begin
        X <= 1'b1;
      end
    end
  end

endmodule

